import{_ as a,o,c as t,ag as r}from"./chunks/framework.BYehg5q7.js";const h=JSON.parse('{"title":"Folder Backup","description":"","frontmatter":{},"headers":[],"relativePath":"guide/folder-backup.md","filePath":"guide/folder-backup.md","lastUpdated":1772866180000}'),s={name:"guide/folder-backup.md"};function l(i,e,n,p,d,u){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="folder-backup" tabindex="-1">Folder Backup <a class="header-anchor" href="#folder-backup" aria-label="Permalink to &quot;Folder Backup&quot;">​</a></h1><p>Folder backup automatically saves your getbased data to a local folder on your computer using the <strong>File System Access API</strong>. This gives you a portable backup file that lives outside the browser — on your local drive, Proton Drive, Dropbox, NAS, or anywhere you choose.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><ol><li>Go to <strong>Settings → Data → Folder Backup</strong></li><li>Click <strong>Pick Folder</strong> and choose a destination</li><li>Done — backups happen automatically from now on</li></ol><p>The folder handle is persisted across browser sessions, so you only need to pick the folder once. If the browser loses access (e.g., after clearing site data), you&#39;ll be prompted to re-select.</p><h2 id="what-gets-saved" tabindex="-1">What Gets Saved <a class="header-anchor" href="#what-gets-saved" aria-label="Permalink to &quot;What Gets Saved&quot;">​</a></h2><p>Each backup is a full snapshot of your getbased database:</p><ul><li>All profiles and their lab entries</li><li>Context cards, notes, supplements, cycle data</li><li>Chat history and conversation threads</li><li>Custom personalities and marker definitions</li><li>API keys and app settings</li></ul><p>Two files are written to your chosen folder:</p><ul><li><strong><code>getbased-backup-latest.json</code></strong> — always-current snapshot, overwritten on each backup</li><li><strong><code>getbased-backup-YYYY-MM-DD.json</code></strong> — daily dated snapshot, one per day (up to 30 days retained)</li></ul><h2 id="when-backups-run" tabindex="-1">When Backups Run <a class="header-anchor" href="#when-backups-run" aria-label="Permalink to &quot;When Backups Run&quot;">​</a></h2><p>A backup is triggered automatically after data changes (same debounce as the IndexedDB auto-backup — 5 minutes after the last change). You can also trigger a manual backup from the Settings panel.</p><h2 id="browser-support" tabindex="-1">Browser Support <a class="header-anchor" href="#browser-support" aria-label="Permalink to &quot;Browser Support&quot;">​</a></h2><p>Folder backup requires the <strong>File System Access API</strong>, which is available in:</p><ul><li>Chrome / Chromium 86+</li><li>Edge 86+</li><li>Opera 72+</li></ul><p>Firefox and Safari do not support this API. The folder backup option is automatically hidden on unsupported browsers. Use <a href="./json-export-import.html">JSON Export</a> as your portable backup on those browsers.</p><h2 id="restoring-from-a-folder-backup" tabindex="-1">Restoring from a Folder Backup <a class="header-anchor" href="#restoring-from-a-folder-backup" aria-label="Permalink to &quot;Restoring from a Folder Backup&quot;">​</a></h2><p>Folder backup files are standard getbased JSON exports. To restore:</p><ol><li>Open getbased in any browser</li><li>Drop the backup <code>.json</code> file onto the import drop zone</li><li>Data is merged into your current profile</li></ol><p>For full database bundles (multi-profile backups), the import process handles profile merging automatically. See <a href="./json-export-import.html#database-bundles">JSON Export &amp; Import</a> for details.</p>',20)])])}const b=a(s,[["render",l]]);export{h as __pageData,b as default};
